import{_ as e,c as o,o as c,R as d}from"./chunks/framework.Cfz5bXfs.js";const _=JSON.parse('{"title":"腹灵 F12 68 键 RGB","description":"","frontmatter":{},"headers":[],"relativePath":"tools/F12.md","filePath":"tools/F12.md","lastUpdated":1701168739000}'),l={name:"tools/F12.md"},i=d('<h1 id="腹灵-f12-68-键-rgb" tabindex="-1">腹灵 F12 68 键 RGB <a class="header-anchor" href="#腹灵-f12-68-键-rgb" aria-label="Permalink to &quot;腹灵 F12 68 键 RGB&quot;">​</a></h1><h2 id="fn-esc-q-w-e-r-win-back-进入功能模式" tabindex="-1">FN + ESC\\Q\\W\\E\\R\\Win\\BACK\\ 进入功能模式 <a class="header-anchor" href="#fn-esc-q-w-e-r-win-back-进入功能模式" aria-label="Permalink to &quot;FN + ESC\\Q\\W\\E\\R\\Win\\BACK\\ 进入功能模式&quot;">​</a></h2><ol><li><code>FN + ESC</code> : 长按三秒，恢复出厂设置</li><li><code>FN + Q\\W\\E\\</code> : 长按三秒开始蓝牙广播设备，短按进入设备切换</li><li><code>FN + R</code> : 长按三秒搜索接收器配对</li><li><code>FN + Win</code> ： 锁或解锁WIN键，带记忆功能</li><li><code>FN + BACK</code> : 查询电量，“<code>0～1</code>” <code>10</code>颗<code>LED</code>灯绿色长亮提示如下： <ul><li><code>4.2V</code> 对<code>100%</code>，<code>10</code>个键显示绿灯；</li><li><code>3.9V</code> 对<code>75%</code>，<code>8</code>个键显示绿灯；</li><li><code>3.6V</code> 对<code>50%</code>，<code>5</code>个键显示绿灯；</li><li><code>3.3V</code> 对<code>25%</code>，<code>3</code>个键显示绿灯；</li></ul></li></ol><blockquote><p>充电指示（仅蓝牙模式显示）： <code>BACK</code> 键 <code>1</code> 次/秒蓝色光闪烁，充满后恢复灯效</p><p>低压指示：<code>BACK</code> 键 <code>3</code> 次/秒红光闪烁</p></blockquote><h2 id="fn-复合按键组合功能" tabindex="-1">FN + 复合按键组合功能 <a class="header-anchor" href="#fn-复合按键组合功能" aria-label="Permalink to &quot;FN + 复合按键组合功能&quot;">​</a></h2><ol><li><p><code>FN + 1!</code>：<code>F1</code></p></li><li><p><code>FN + 2@</code>：<code>F2</code></p></li><li><p><code>FN + 3#</code>：<code>F3</code></p></li><li><p><code>FN + 4$</code>：<code>F4</code></p></li><li><p><code>FN + 5%</code>：<code>F5</code></p></li><li><p><code>FN + 6^</code>：<code>F6</code></p></li><li><p><code>FN + 7&amp;</code>：<code>F7</code></p></li><li><p><code>FN + 8*</code>：<code>F8</code></p></li><li><p><code>FN + 9(</code>：<code>F9</code></p></li><li><p><code>FN + 0)</code>：<code>F10</code></p></li><li><p><code>FN + -_</code>：<code>F11</code></p></li><li><p><code>FN + =+!</code>：<code>F12</code></p></li><li><p><code>FN + I</code>：<code>PRT</code></p></li><li><p><code>FN + O</code>：<code>SCR</code></p></li><li><p><code>FN + P</code>：<code>PAUSE</code></p></li><li><p><code>FN + J</code>：<code>INS</code></p></li><li><p><code>FN + K</code>：<code>HOME</code></p></li><li><p><code>FN + L</code>：<code>END</code></p></li><li><p><code>FN + 右ALT</code>：<code>APP</code></p></li><li><p><code>FN + [{</code>：音量<code>-</code></p></li><li><p><code>FN + ]}</code>：音量<code>+</code></p></li><li><p><code>FN + \\|</code>：静音</p></li></ol><h2 id="fn-灯光" tabindex="-1">FN + 灯光 <a class="header-anchor" href="#fn-灯光" aria-label="Permalink to &quot;FN + 灯光&quot;">​</a></h2><ol><li><code>FN + 右CTRL</code> 灯光模式切换</li><li><code>FN + 右SHIFT</code> 灯光颜色七色单色切换</li><li><code>FN + PGDN</code> 一键进入长亮模式，默认红色</li></ol><h2 id="fn-方向组合建" tabindex="-1">FN + 方向组合建 <a class="header-anchor" href="#fn-方向组合建" aria-label="Permalink to &quot;FN + 方向组合建&quot;">​</a></h2><ol><li><p>灯光亮度调节：<code>FN + ↑↓</code></p><p>通过 <code>FN + ↓</code> 调暗，<code>FN ＋ ↑</code> 调亮，一共五级（ <code>100%</code> - <code>75%</code> - <code>50%</code> - <code>25%</code> - <code>OFF</code>）, 默认为 <code>100％</code> 亮度。调到最低档或最高档时四颗方向键背光 <code>LED</code> 闪 <code>3</code> 次提示。</p></li><li><p>灯光快慢调节：<code>FN + →</code></p><p>通过 <code>FN + ←</code> 调慢，<code>FN + →</code> 调快，一共四级，默认为第三级。调到最慢档或最快档时四颗方向键背光闪烁 <code>3</code> 次提示。</p></li></ol>',10),a=[i];function p(F,t,N,r,n,s){return c(),o("div",null,a)}const f=e(l,[["render",p]]);export{_ as __pageData,f as default};
